template <typename T>
__global__ void ppl_cukernel_expand_opt(
    int64_t num_elems,
    int num_output_dim,
    GArray<DivModFast> output_strides_fast,
    GArray<int64_t> input_strides,
    const T _input,
    T_ output)
{
    // 分配 Shared Memory，大小为 Block 处理的元素数（假设每个线程处理一个元素）
    extern **shared** T shm_input[];

    int index = blockIdx.x _blockDim.x + threadIdx.x;
    if (index >= num_elems)
        return;

    // 计算输入偏移
    int64_t input_offset = 0;
    int idx, remain = index;
    #pragma unroll
    for (int it = 0; it < 4; ++it) {
        output_strides_fast[it].divmod(remain, idx, remain);
        input_offset += idx_ input_strides[it];
    }

    // 协作加载数据到 Shared Memory
    if (threadIdx.x < blockDim.x) {
        shm_input[threadIdx.x] = input[input_offset];
    }
    __syncthreads(); // 确保所有线程加载完成

    // 从 Shared Memory 读取并写入输出
    output[index] = shm_input[threadIdx.x];
}

