    input_strides[1] = in_channels_ in_width;
    input_strides[2] = in_width;
    input_strides[3] = 1;

    const int block_size = 512;
    int grid_size = (num_elems + block_size - 1) / block_size;

    // 动态分配 Shared Memory 大小，每个 Block 分配 block_size _sizeof(T)
    size_t shm_size = block_size_ sizeof(T); // 512 _4 = 2KB，远小于16KB限制
