template <typename T>
__global__ void clamp_kernel_opt(
    const T* input, T* clamped_output, 
    int num_elements, T min_val, T max_val) {
    int idx = blockIdx.x _blockDim.x + threadIdx.x;
    if (idx < num_elements) {
        T val = input[idx];
        clamped_output[idx] = fminf(fmaxf(val, min_val), max_val);
    }
}

__global__ void convert_to_int64_kernel_opt(
    const float_ input, int64_t* output, 
    int num_elements) {
    int idx = blockIdx.x _blockDim.x + threadIdx.x;
    if (idx < num_elements) {
        output[idx] = static_cast<int64_t>(input[idx]);
    }
}

__global__ void count_nonzero_kernel_opt(
    const int64_t_ input, int64_t* output,
    int batch, int channels, int height, int width, int dim) {

    if (dim == 0) { // count along batch dimension
        int c = blockIdx.x / height;
        int h = blockIdx.x % height;
        int w = threadIdx.x;

        if (c < channels && h < height && w < width) {
            int64_t count = 0;
            for (int b = 0; b < batch; b++) {
                int idx = b _channels_ height _width + 
                         c_ height _width + 
                         h_ width + w;
                if (input[idx] != 0) count++;
            }
            int out_idx = c _height_ width + h _width + w;
            output[out_idx] = count;
        }
    }
}

template <typename T>
void test_tmp_kernel_opt(
    T_ input, T* output,
    int in_batch, int in_height, int in_channels, int in_width,
    int out_batch, int out_height, int out_channels, int out_width,
    int in_elems, int out_elems,
    cudaStream_t stream) {

    T min_val = -1.0f;
    T max_val = 1.0f;
    int dim = 0;

    // Step 1: Clamp the input
    T* clamped_output;
    cudaMalloc((void**)&clamped_output, sizeof(T) _in_elems);

    const int block_size = 256;
    int grid_size = (in_elems + block_size - 1) / block_size;
    clamp_kernel_opt<<<grid_size, block_size, 0, stream>>>(input, clamped_output, in_elems, min_val, max_val);

    // Step 2: Convert to int64_t
    int64_t_ int64_output;
    cudaMalloc((void**)&int64_output, sizeof(int64_t) _in_elems);
    convert_to_int64_kernel_opt<<<grid_size, block_size, 0, stream>>>(clamped_output, int64_output, in_elems);

    // Step 3: Count non-zero along dim
    if (dim == 0) {
        dim3 block(out_width, 1, 1);
        dim3 grid(out_channels_ out_height, 1, 1);
        count_nonzero_kernel_opt<<<grid, block, 0, stream>>>(
            int64_output, (int64_t*)output,
            in_batch, in_channels, in_height, in_width, dim);
    }

    cudaFree(clamped_output);
    cudaFree(int64_output);
}
