__global__ void fused_logsoftmax_argmin_kernel(const float* input, int* output, int batch_size, int feature_size) {
    const int row_idx = blockIdx.x;
    const int tid = threadIdx.x;
    const int vec_feature_size = feature_size / VEC_SIZE;

    extern __shared__ **align**(16) char shared_buf[];
    float* shm_row = reinterpret_cast<float*>(shared_buf);
    float* shared_max = reinterpret_cast<float*>(shared_buf + feature_size _sizeof(float));
    float_ shared_sum = shared_max + blockDim.x;
    float* shared_min = shared_sum + blockDim.x;
    int* shared_min_idx = reinterpret_cast<int*>(shared_min + blockDim.x);

    // 协作加载输入数据到Shared Memory
    const float* global_row = input + row_idx _feature_size;
    for (int i = tid_ VEC_SIZE; i < vec_feature_size _VEC_SIZE; i += blockDim.x_ VEC_SIZE) {
        float4 vec_data = load_float4<VEC_SIZE>(global_row + i);
        store_float4<VEC_SIZE>(&shm_row[i], vec_data);
    }
    // 处理剩余元素
    for (int i = vec_feature_size _VEC_SIZE + tid; i < feature_size; i += blockDim.x) {
        shm_row[i] = global_row[i];
    }
    __syncthreads();

    float thread_max = -INFINITY;
    float thread_sum = 0.0f;
    float thread_min = INFINITY;
    int thread_min_idx = 0;

    // Phase 1: Compute max and sum
    for (int i = tid_ VEC_SIZE; i < vec_feature_size _VEC_SIZE; i += blockDim.x_ VEC_SIZE) {
        float4 vec_data = load_float4<VEC_SIZE>(shm_row + i);
        float vals[4] = {vec_data.x, vec_data.y, vec_data.z, vec_data.w};

        for (int v = 0; v < VEC_SIZE; v++) {
            thread_max = fmaxf(thread_max, vals[v]);
        }
    }

    // Handle remaining elements
    for (int i = vec_feature_size _VEC_SIZE + tid; i < feature_size; i += blockDim.x) {
        thread_max = fmaxf(thread_max, shm_row[i]);
    }

    // Reduce max
    shared_max[tid] = thread_max;
    __syncthreads();
    for (int s = blockDim.x/2; s > 0; s >>= 1) {
        if (tid < s) {
            shared_max[tid] = fmaxf(shared_max[tid], shared_max[tid + s]);
        }
        __syncthreads();
    }
    float row_max = shared_max[0];

    // Compute sum exp
    for (int i = tid_ VEC_SIZE; i < vec_feature_size _VEC_SIZE; i += blockDim.x_ VEC_SIZE) {
        float4 vec_data = load_float4<VEC_SIZE>(shm_row + i);
        float vals[4] = {vec_data.x, vec_data.y, vec_data.z, vec_data.w};

        for (int v = 0; v < VEC_SIZE; v++) {
            thread_sum += expf(vals[v] - row_max);
        }
    }

    // Handle remaining elements
    for (int i = vec_feature_size _VEC_SIZE + tid; i < feature_size; i += blockDim.x) {
        thread_sum += expf(shm_row[i] - row_max);
    }

    // Reduce sum
    shared_sum[tid] = thread_sum;
    __syncthreads();
    for (int s = blockDim.x/2; s > 0; s >>= 1) {
        if (tid < s) {
            shared_sum[tid] += shared_sum[tid + s];
        }
        __syncthreads();
    }
    float log_sum_exp = row_max + logf(shared_sum[0]);

    // Phase 2: Find argmin
    for (int i = tid_ VEC_SIZE; i < vec_feature_size _VEC_SIZE; i += blockDim.x_ VEC_SIZE) {
        float4 vec_data = load_float4<VEC_SIZE>(shm_row + i);
        float4 softmax_val = {vec_data.x - log_sum_exp, vec_data.y - log_sum_exp,
                             vec_data.z - log_sum_exp, vec_data.w - log_sum_exp};

        float vals[4] = {softmax_val.x, softmax_val.y, softmax_val.z, softmax_val.w};
        for (int v = 0; v < VEC_SIZE; v++) {
            int pos = i + v;
            if (vals[v] < thread_min) {
                thread_min = vals[v];
                thread_min_idx = pos;
            } else if (vals[v] == thread_min && pos < thread_min_idx) {
                thread_min_idx = pos;
            }
        }
    }

    // Handle remaining elements
    for (int i = vec_feature_size _VEC_SIZE + tid; i < feature_size; i += blockDim.x) {
        float val = shm_row[i] - log_sum_exp;
        if (val < thread_min) {
            thread_min = val;
            thread_min_idx = i;
        } else if (val == thread_min && i < thread_min_idx) {
            thread_min_idx = i;
        }
    }

    // Reduce argmin
    shared_min[tid] = thread_min;
    shared_min_idx[tid] = thread_min_idx;
    __syncthreads();

    for (int s = blockDim.x/2; s > 0; s >>= 1) {
        if (tid < s) {
            float current_min = shared_min[tid];
            float neighbor_min = shared_min[tid + s];
            int current_idx = shared_min_idx[tid];
            int neighbor_idx = shared_min_idx[tid + s];

            if (neighbor_min < current_min || 
                (neighbor_min == current_min && neighbor_idx < current_idx)) {
                shared_min[tid] = neighbor_min;
                shared_min_idx[tid] = neighbor_idx;
            }
        }
        __syncthreads();
    }

    if (tid == 0) {
        output[row_idx] = shared_min_idx[0];
    }
}

