import json
from typing import Dict, List, Any, Set, Union
from collections import defaultdict

def inspect_data_structure(data: Any, max_depth: int = 3) -> Dict[str, Any]:
    """检查数据结构"""
    inspection = {
        "type": type(data).__name__,
        "length": len(data) if hasattr(data, '__len__') else None
    }

    if isinstance(data, dict):
        inspection["keys"] = list(data.keys())[:10]  # 只显示前10个key
        if data and max_depth > 0:
            first_key = list(data.keys())[0]
            inspection["first_value_structure"] = inspect_data_structure(
                data[first_key], max_depth - 1
            )
    elif isinstance(data, list) and data and max_depth > 0:
        inspection["first_item_structure"] = inspect_data_structure(
            data[0], max_depth - 1
        )

    return inspection

def extract_system_prompts(data: Union[Dict, List]) -> Dict[str, Set[str]]:
    """
    提取所有 system_prompt 并检查一致性
    返回每个 kernel 的 system_prompt 集合
    """
    system_prompts = defaultdict(set)

    # 处理可能是列表或字典的数据结构
    if isinstance(data, list):
        # 如果是列表，假设每个元素是一个 kernel 的数据
        for idx, kernel_data in enumerate(data):
            kernel_name = kernel_data.get("kernel_name", f"kernel_{idx}")
            improvement_steps = kernel_data.get("improvement_steps", [])

            for step in improvement_steps:
                action = step.get("action", {})
                system_prompt = action.get("system_prompt", "")
                if system_prompt:
                    system_prompts[kernel_name].add(system_prompt)

    elif isinstance(data, dict):
        # 如果是字典，假设 key 是 kernel_name
