    int stride = blockDim.x * gridDim.x;
    constexpr int N = sizeof(VecType) / sizeof(T);
    for (; idx * N < num_elements; idx += stride) {
        VecType in_val;
        int offset = idx * N;
        if (offset + N <= num_elements) {
            in_val = *reinterpret_cast<const VecType*>(input + offset);
        } else {
            // Handle the remaining elements
            T temp[N];
            for (int i = 0; i < N; ++i) {
                temp[i] = (offset + i < num_elements) ? input[offset + i] : T(0);
            }
            in_val = *reinterpret_cast<VecType*>(temp);
        }
        T out_val[N];
        #pragma unroll
        for (int i = 0; i < N; ++i) {
            out_val[i] = fmodf(reinterpret_cast<T*>(&in_val)[i], divisor) - divisor;
        }
        if (offset + N <= num_elements) {
            *reinterpret_cast<VecType*>(output + offset) = *reinterpret_cast<VecType*>(out_val);
        } else {
            for (int i = 0; i < N; ++i) {
                if (offset + i < num_elements) {
                    output[offset + i] = out_val[i];
                }
            }
        }
    }
}

